import React from 'react';
import { ChickenData, GamePhase } from '../types';
import Chicken from './Chicken';
import Background from './Background';

interface TrackProps {
  chickens: ChickenData[];
  phase: GamePhase;
  winner: number | null;
  selectedChicken: number | null;
  countdownValue: number;
}

const Track: React.FC<TrackProps> = ({ chickens, phase, winner, selectedChicken, countdownValue }) => {
  return (
    <div className="track-container">
      {/* Farm background */}
      <div className="track-background">
        <Background />
      </div>

      {/* BAAS watermark */}
      <div className="track-watermark">BAAS</div>

      {/* Tracks */}
      <div className="tracks-area">
        {chickens.map((chicken) => (
          <div
            key={chicken.id}
            className={`track-lane ${selectedChicken === chicken.id ? 'track-lane-selected' : ''}`}
          >
            {/* Lane number panel */}
            <div className="lane-number">
              <span>{chicken.id}</span>
            </div>

            {/* Dirt track */}
            <div className="dirt-track">
              {/* Checkered starting line */}
              <div className="starting-line">
                {Array.from({ length: 8 }, (_, i) => (
                  <div
                    key={i}
                    className={`checker-cell ${i % 2 === 0 ? 'checker-black' : 'checker-white'}`}
                  />
                ))}
              </div>

              {/* Finish line */}
              <div className="finish-line">
                {Array.from({ length: 8 }, (_, i) => (
                  <div
                    key={i}
                    className={`checker-cell ${i % 2 === 0 ? 'checker-black' : 'checker-white'}`}
                  />
                ))}
                <span className="finish-label">FINISH</span>
              </div>

              {/* Chicken */}
              <Chicken
                chicken={chicken}
                phase={phase}
                isWinner={winner === chicken.id}
              />
            </div>
          </div>
        ))}
      </div>

      {/* Countdown overlay */}
      {phase === 'countdown' && (
        <div className="countdown-overlay">
          <div className="countdown-number">{countdownValue}</div>
        </div>
      )}

      {/* Result overlay */}
      {phase === 'result' && winner !== null && (
        <div className="result-overlay">
          <div className="result-banner">
            <div className="result-winner-text">
              🐔 Chicken #{winner} Wins!
            </div>
            <div className="result-chicken-name">
              {chickens.find(c => c.id === winner)?.name}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Track;
